def range_summary(nums):
    if not nums:
        return ''

    sorted_nums = sorted(set(nums))
    result = []
    for i in range(1, len(sorted_nums)):
        if sorted_nums[i] == sorted_nums[i - 1] + 1:
            result.append(f'{sorted_nums[i-1]}-{sorted_nums[i]}')
        else:
            result.append(str(sorted_nums[i-1]))

    return ','.join(result)
